// Tab component
function Tab({
  file,
  isActive,
  onSelect,
  onClose,
}: {
  file: string;
  isActive: boolean;
  onSelect: () => void;
  onClose: (e: React.MouseEvent) => void;
}) {
  const ext = file.split(".").pop();
  let iconColor = "text-[#6b6b6b]";
  if (ext === "md") iconColor = "text-[#519aba]";
  else if (ext === "css") iconColor = "text-[#56b6c2]";

  return (
    <div
      onClick={onSelect}
      className={`group flex items-center gap-2 px-3 h-9 cursor-pointer border-r border-[#2d2d2d] ${
        isActive
          ? "bg-[#1e1e1e] text-white"
          : "bg-[#2d2d2d] text-[#a0a0a0] hover:text-white"
      }`}
    >
      <svg className={`w-4 h-4 ${iconColor}`} fill="currentColor" viewBox="0 0 24 24">
        <path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6zm-1 2l5 5h-5V4z" />
      </svg>
      <span className="text-sm">{file}</span>
      <button
        onClick={onClose}
        className="ml-1 p-0.5 rounded hover:bg-[#3d3d3d] opacity-0 group-hover:opacity-100 transition-opacity"
      >
        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
        </svg>
      </button>
    </div>
  );
}

// Breadcrumb component
function Breadcrumb({ file }: { file: string }) {
  const parts = ["portfolio", file];
  return (
    <div className="flex items-center gap-1 h-6 px-4 bg-[#1e1e1e] text-[#a0a0a0] text-xs border-b border-[#2d2d2d]">
      {parts.map((part, idx) => (
        <React.Fragment key={idx}>
          {idx > 0 && (
            <svg className="w-3 h-3 text-[#6b6b6b]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
            </svg>
          )}
          <span className="hover:text-white cursor-pointer">{part}</span>
        </React.Fragment>
      ))}
    </div>
  );
}

// Code view with line numbers
function CodeView({ content }: { content: string }) {
  const lines = content.split("\n");

  return (
    <div className="flex h-full overflow-auto font-mono text-sm">
      {/* Line numbers gutter */}
      <div className="flex flex-col items-end pr-4 pl-4 py-2 bg-[#1e1e1e] text-[#6b6b6b] select-none border-r border-[#2d2d2d] sticky left-0">
        {lines.map((_, idx) => (
          <div key={idx} className="leading-6">
            {idx + 1}
          </div>
        ))}
      </div>

      {/* Code content */}
      <div className="flex-1 py-2 pl-4 pr-4">
        {lines.map((line, idx) => {
          // Simple syntax highlighting for markdown
          let className = "text-[#d4d4d4] leading-6";
          if (line.startsWith("# ")) className = "text-[#569cd6] leading-6 font-bold text-lg";
          else if (line.startsWith("## ")) className = "text-[#4ec9b0] leading-6 font-semibold";
          else if (line.startsWith("### ")) className = "text-[#dcdcaa] leading-6 font-medium";
          else if (line.startsWith("- ")) className = "text-[#ce9178] leading-6";
          else if (line.startsWith("**")) className = "text-[#c586c0] leading-6 font-semibold";

          return (
            <div key={idx} className={className}>
              {line || "\u00A0"}
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default function EditorPanel({
  openFiles,
  activeFile,
  onSelectTab,
  onCloseTab,
}: Props) {
  // Welcome screen when no files are open
  if (openFiles.length === 0 || !activeFile) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center bg-[#1e1e1e] text-[#6b6b6b]">
        <svg className="w-24 h-24 mb-4 text-[#3d3d3d]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" />
        </svg>
        <h2 className="text-xl text-[#a0a0a0] mb-2">Welcome to Karthik's Portfolio</h2>
        <p className="text-sm">Click a file in the explorer to get started</p>
      </div>
    );
  }

  const content = fileContents[activeFile] || `// Content for ${activeFile}`;

  return (
    <div className="flex-1 flex flex-col bg-[#1e1e1e] overflow-hidden">
      {/* Tab bar */}
      <div className="flex bg-[#252525] border-b border-[#2d2d2d] overflow-x-auto">
        {openFiles.map((file) => (
          <Tab
            key={file}
            file={file}
            isActive={file === activeFile}
            onSelect={() => onSelectTab(file)}
            onClose={(e) => {
              e.stopPropagation();
              onCloseTab(file);
            }}
          />
        ))}
      </div>

      {/* Breadcrumb */}
      <Breadcrumb file={activeFile} />

      {/* Editor content */}
      <div className="flex-1 overflow-hidden">
        <CodeView content={content} />
      </div>
    </div>
  );
}
